module top_module(A, B, obf_sel, C);parameter WIDTH = 8;
   input [WIDTH-1:0] A, B;
   input obf_sel;
   output [WIDTH-1:0] C;

   reg [WIDTH-1:0]    C_reg;

   always @(*)
   begin
      if (obf_sel == 0)
         C_reg = A + B;
      else
         C_reg = A - B;
   end

   assign C = C_reg;
endmodule
